module shift_register_8bit(
    input clk, 
    input rst, 
    input load, 
    input [7:0] data, 
    output reg serial_out);

    reg [7:0] data_reg;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            data_reg <= 8'b00000000;
            serial_out <= 0;
        end else if (load) begin
            data_reg <= data;
        end else begin
            serial_out <= data_reg[7];
            data_reg <= {data_reg[6:0], 1'b0};
        end
    end
endmodule
